from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetProductsNode(BaseNode):
    name = "Prism: Get Products"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_output("products", "list")
        self.add_output("count", "int")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        entity = inputs.get('entity') or {}
        if core is None:
            self.log_error("No PrismCore provided.")
            return {'products': [], 'count': 0}
        try:
            products = []
            for attr in ('getProductsFromEntity', 'getProducts'):
                if hasattr(core.products, attr):
                    products = getattr(core.products, attr)(entity) or []
                    break
            self.log_info(f"Found {len(products)} product(s).")
            return {'products': list(products), 'count': len(products)}
        except Exception as e:
            self.log_error(f"getProducts failed: {e}")
            return {'products': [], 'count': 0}

def register_node():
    return PrismGetProductsNode
